sql:
SELECT school_name, total_budget
FROM schools
WHERE total_budget > (SELECT AVG(total_budget) FROM schools);

SELECT school_name
FROM schools
WHERE budget_per_student > (SELECT AVG(budget_per_student) FROM schools);

SELECT school_name, total_students
FROM schools
ORDER BY total_students DESC;

SELECT SUM(total_budget) AS total_budget
FROM budgets
WHERE budget_category = 'Facilities' AND year = 1;

SELECT school_name, budget_per_student
FROM schools
WHERE budget_per_student > (
    SELECT AVG(budget_per_student) FROM schools
)
AND school_district = (
    SELECT school_district FROM schools WHERE school_id = 2
);

external_knowledge:
- 'Strong math performance' refers to high average scores and passing rates in Math 'State Test'.;
- 'Overseen by an administrator' means that there is at least one administrator in the school.;
- The average passing rate threshold of 80% is a measure of proficiency.;
- Budget over $1 million indicates significant financial resources available for the school.;
- 'Total average math scores' and 'average passing rates' are aggregated metrics for Math 'State Test' within the specified period.;

